CREATE TABLE IF NOT EXISTS "user" (
  "id" TEXT PRIMARY KEY NOT NULL,
  "name" TEXT,
  "email" TEXT,
  "emailVerified" INTEGER,
  "image" TEXT,
  "role" TEXT NOT NULL DEFAULT 'catalog',
  "passwordHash" TEXT,
  "createdAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  "updatedAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000)
);
INSERT INTO "user" ("id","name","email","emailVerified","image","role","passwordHash","createdAt","updatedAt") VALUES('b2b0caf8-3d7a-4e55-a8ff-7e19633208c7','Dev Owner','owner@base-ecommerce.local',1773615134244,NULL,'owner','$2b$10$OOFSwyiEBroBPlR6ua1JeuDNH73RnEI.SFerUN9QXNDG3lA3ppCge',1773615134244,1773615134244);
CREATE TABLE IF NOT EXISTS "account" (
  "userId" TEXT NOT NULL,
  "type" TEXT NOT NULL,
  "provider" TEXT NOT NULL,
  "providerAccountId" TEXT NOT NULL,
  "refresh_token" TEXT,
  "access_token" TEXT,
  "expires_at" INTEGER,
  "token_type" TEXT,
  "scope" TEXT,
  "id_token" TEXT,
  "session_state" TEXT,
  PRIMARY KEY ("provider", "providerAccountId"),
  FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "verificationToken" (
  "identifier" TEXT NOT NULL,
  "token" TEXT NOT NULL,
  "expires" INTEGER NOT NULL,
  PRIMARY KEY ("identifier", "token")
);
CREATE TABLE IF NOT EXISTS "passwordResetToken" (
  "token" TEXT PRIMARY KEY NOT NULL,
  "userId" TEXT NOT NULL,
  "expires" INTEGER NOT NULL,
  "createdAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "cart" (
  "id" TEXT PRIMARY KEY NOT NULL,
  "userId" TEXT NOT NULL,
  "createdAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  "updatedAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE CASCADE
);
INSERT INTO "cart" ("id","userId","createdAt","updatedAt") VALUES('aa38b784-84a3-4d9d-9981-eb758568c3a7','b2b0caf8-3d7a-4e55-a8ff-7e19633208c7',1773615134244,1774203572397);
CREATE TABLE IF NOT EXISTS "cartItem" (
  "cartId" TEXT NOT NULL,
  "variantId" TEXT NOT NULL,
  "productId" TEXT NOT NULL,
  "name" TEXT NOT NULL,
  "variantName" TEXT NOT NULL,
  "href" TEXT NOT NULL,
  "currency" TEXT NOT NULL,
  "unitPriceCents" INTEGER NOT NULL,
  "stockOnHand" INTEGER NOT NULL,
  "quantity" INTEGER NOT NULL,
  "unavailableReason" TEXT,
  "updatedAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  PRIMARY KEY ("cartId", "variantId"),
  FOREIGN KEY ("cartId") REFERENCES "cart" ("id") ON DELETE CASCADE
);
INSERT INTO "cartItem" ("cartId","variantId","productId","name","variantName","href","currency","unitPriceCents","stockOnHand","quantity","unavailableReason","updatedAt") VALUES('aa38b784-84a3-4d9d-9981-eb758568c3a7','d4ac5f5e-c432-4667-937f-7f1356e7674a','2e06737a-1191-4148-83f3-d95ff8d7f5aa','AM5 Motherboard X','ATX Edition','/catalog/pc-components/am5-motherboard-x','MXN',229900,8,2,NULL,1774203572345);
CREATE TABLE IF NOT EXISTS "authRefreshSession" (
  "id" TEXT PRIMARY KEY NOT NULL,
  "userId" TEXT NOT NULL,
  "surface" TEXT NOT NULL DEFAULT 'storefront',
  "tokenHash" TEXT NOT NULL,
  "deviceId" TEXT NOT NULL,
  "userAgent" TEXT,
  "ipHash" TEXT,
  "createdAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  "lastSeenAt" INTEGER NOT NULL DEFAULT (unixepoch('now') * 1000),
  "idleExpiresAt" INTEGER NOT NULL,
  "absoluteExpiresAt" INTEGER NOT NULL,
  "revokedAt" INTEGER,
  "rotatedFromId" TEXT,
  FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE CASCADE
);
